
"""
Startup Idea Validator — Reality-check your idea in 2 minutes

Setup:
  pip install -r requirements.txt
  uvicorn main:app --reload
  open http://localhost:8000
"""
import os, sqlite3, hashlib, secrets
from fastapi import FastAPI, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from fastapi.responses import HTMLResponse
from pydantic import BaseModel
import httpx
from dotenv import load_dotenv

load_dotenv()
GROQ_API_KEY = os.getenv("GROQ_API_KEY", "")
DB_FILE      = os.getenv("DB_FILE", "/tmp/startup_idea_validator.db")
SYSTEM_PROMPT = "You are a specialised AI tool: Startup Idea Validator.\n\nYou are an experienced business strategist. Give advice that is specific to the user's situation, not generic.\n\nYour job: Describe your startup idea. Get an honest validation with market size, competition, and key risks.\n\nThe user will provide: idea description, target market, revenue model. Use all of this information to personalise your response.\n\nOutput format: Structure your response as clear numbered steps. Each step on its own line, actionable and specific. Tell the user exactly what to do.\n\nQuality rules:\n- Be specific to what the user has actually provided \u2014 never give generic advice that ignores their inputs\n- Do not start with filler openers like Sure, Great, Certainly, or Of course\n- Do not explain what you are about to do \u2014 just do it\n- Do not add unnecessary disclaimers unless they are genuinely important\n- If the user's input is vague, make reasonable assumptions and state them briefly\n- Aim for depth over length \u2014 one specific, useful insight beats three generic ones"

app = FastAPI(title="Startup Idea Validator")
app.add_middleware(CORSMiddleware, allow_origins=["*"], allow_methods=["*"], allow_headers=["*"])


# ── Database ───────────────────────────────────────────────────────────────────

def get_db():
    conn = sqlite3.connect(DB_FILE)
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    with get_db() as conn:
        conn.executescript("""
            CREATE TABLE IF NOT EXISTS users (
                id       INTEGER PRIMARY KEY AUTOINCREMENT,
                email    TEXT UNIQUE NOT NULL,
                name     TEXT,
                password TEXT NOT NULL,
                token    TEXT UNIQUE,
                ts       TEXT DEFAULT (datetime(\'now\'))
            );
            CREATE TABLE IF NOT EXISTS queries (
                id     INTEGER PRIMARY KEY AUTOINCREMENT,
                prompt TEXT NOT NULL,
                result TEXT,
                ts     TEXT DEFAULT (datetime(\'now\'))
            );
        """)
        conn.commit()

init_db()

# Auth is optional and can be toggled on/off in the plan. If enabled, these endpoints will be included in the generated app.

class AuthRequest(BaseModel):
    email: str
    password: str
    name: str = ""

def hash_pw(pw: str) -> str:
    return hashlib.sha256(pw.encode()).hexdigest()


# ── Auth endpoints ─────────────────────────────────────────────────────────────

@app.post("/api/auth/signup")
def signup(req: AuthRequest):
    token = secrets.token_hex(32)
    try:
        with get_db() as conn:
            conn.execute(
                "INSERT INTO users (email, name, password, token) VALUES (?, ?, ?, ?)",
                (req.email.lower(), req.name or req.email.split("@")[0], hash_pw(req.password), token)
            )
            conn.commit()
    except sqlite3.IntegrityError:
        raise HTTPException(400, detail="Email already registered")
    return {"email": req.email, "name": req.name or req.email.split("@")[0], "token": token}

@app.post("/api/auth/login")
def login(req: AuthRequest):
    with get_db() as conn:
        row = conn.execute(
            "SELECT * FROM users WHERE email = ? AND password = ?",
            (req.email.lower(), hash_pw(req.password))
        ).fetchone()
    if not row:
        raise HTTPException(401, detail="Invalid email or password")
    return {"email": row["email"], "name": row["name"], "token": row["token"]}

